@page "/apply/personal-info"
@rendermode InteractiveServer
@using sv_3df931229ad2486fa7700186ca801ed3.Models
@using sv_3df931229ad2486fa7700186ca801ed3.Services
@inject WizardState Wizard
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<h1>Step 1: Personal Information</h1>

<EditForm Model="Wizard.Data.PersonalInfo" FormName="personal-info" OnValidSubmit="Next">
    <div class="mb-3">
        <label class="form-label">Name</label>
        <InputText class="form-control" @bind-Value="Wizard.Data.PersonalInfo.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="Wizard.Data.PersonalInfo.Email" />
    </div>
    <div class="mb-3">
        <label class="form-label">Phone</label>
        <InputText class="form-control" @bind-Value="Wizard.Data.PersonalInfo.Phone" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(new WizardProgress
        {
            CurrentStep = 1,
            CompletedSteps = new(Wizard.CompletedSteps)
        });
    }

    private async Task Next()
    {
        Wizard.MarkCompleted(1);
        await ProgressSource.NotifyChangedAsync(new WizardProgress
        {
            CurrentStep = 1,
            CompletedSteps = new(Wizard.CompletedSteps)
        });
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@using sv_3df931229ad2486fa7700186ca801ed3.Models
@using sv_3df931229ad2486fa7700186ca801ed3.Services
@inject WizardState Wizard
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<h1>Step 2: Work Experience</h1>

@for (int i = 0; i < Wizard.Data.Experiences.Count; i++)
{
    var idx = i;
    <div class="card mb-3 p-3">
        <h5>Experience @(idx + 1)</h5>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="Wizard.Data.Experiences[idx].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Job Title</label>
            <input class="form-control" @bind="Wizard.Data.Experiences[idx].Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="Wizard.Data.Experiences[idx].Years" />
        </div>
        @if (Wizard.Data.Experiences.Count > 1)
        {
            <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveExperience(idx)">Remove</button>
        }
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddExperience">+ Add Experience</button>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(new WizardProgress
        {
            CurrentStep = 2,
            CompletedSteps = new(Wizard.CompletedSteps)
        });
    }

    private void AddExperience() => Wizard.Data.Experiences.Add(new());
    private void RemoveExperience(int idx) => Wizard.Data.Experiences.RemoveAt(idx);

    private void Back() => Nav.NavigateTo("/apply/personal-info");

    private async Task Next()
    {
        Wizard.MarkCompleted(2);
        await ProgressSource.NotifyChangedAsync(new WizardProgress
        {
            CurrentStep = 2,
            CompletedSteps = new(Wizard.CompletedSteps)
        });
        Nav.NavigateTo("/apply/references");
    }
}

