@page "/apply/review"
@rendermode InteractiveServer
@using sv_3df931229ad2486fa7700186ca801ed3.Models
@using sv_3df931229ad2486fa7700186ca801ed3.Services
@inject WizardState Wizard
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<h1>Step 4: Review Your Application</h1>

<div class="card mb-3 p-3">
    <h4>Personal Information</h4>
    <dl>
        <dt>Name</dt><dd>@Wizard.Data.PersonalInfo.Name</dd>
        <dt>Email</dt><dd>@Wizard.Data.PersonalInfo.Email</dd>
        <dt>Phone</dt><dd>@Wizard.Data.PersonalInfo.Phone</dd>
    </dl>
</div>

<div class="card mb-3 p-3">
    <h4>Work Experience</h4>
    @foreach (var exp in Wizard.Data.Experiences)
    {
        <div class="mb-2">
            <strong>@exp.Title</strong> at @exp.Company (@exp.Years years)
        </div>
    }
</div>

<div class="card mb-3 p-3">
    <h4>References</h4>
    @foreach (var r in Wizard.Data.References)
    {
        <div class="mb-2">
            <strong>@r.Name</strong> — @r.Relationship (@r.ContactInfo)
        </div>
    }
</div>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (submitted)
{
    <div class="alert alert-success mt-3">Application submitted successfully!</div>
}

@code {
    private bool submitted;

    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(new WizardProgress
        {
            CurrentStep = 4,
            CompletedSteps = new(Wizard.CompletedSteps)
        });
    }

    private void Back() => Nav.NavigateTo("/apply/references");

    private async Task Submit()
    {
        Wizard.MarkCompleted(4);
        await ProgressSource.NotifyChangedAsync(new WizardProgress
        {
            CurrentStep = 4,
            CompletedSteps = new(Wizard.CompletedSteps)
        });
        submitted = true;
    }
}

